#include <bits/stdc++.h>
using namespace std;

// Standard O(n*m) time, O(n*m) space
int lcs_full(const string& a, const string& b) {
    int n = a.size(), m = b.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++)
            if (a[i-1] == b[j-1]) dp[i][j] = dp[i-1][j-1] + 1;
            else                  dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
    return dp[n][m];
}

// Space-optimized: O(min(n,m)) space using two rows
int lcs_optimized(const string& a, const string& b) {
    int n = a.size(), m = b.size();
    // Ensure b is the shorter string
    if (n < m) return lcs_optimized(b, a);
    vector<int> prev(m + 1, 0), cur(m + 1, 0);
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++)
            if (a[i-1] == b[j-1]) cur[j] = prev[j-1] + 1;
            else                  cur[j] = max(prev[j], cur[j-1]);
        swap(prev, cur);
        fill(cur.begin(), cur.end(), 0);
    }
    return prev[m];
}

int main() {
    string a = "ABCBDAB", b = "BDCAB";
    cout << lcs_full(a, b) << "\n";       // 4  (BCAB)
    cout << lcs_optimized(a, b) << "\n"; // 4
}

#include <bits/stdc++.h>
using namespace std;

// O(n^2) — correct but slow for large n
int lis_slow(vector<int>& arr) {
    int n = arr.size();
    vector<int> dp(n, 1);
    for (int i = 1; i < n; i++)
        for (int j = 0; j < i; j++)
            if (arr[j] < arr[i]) dp[i] = max(dp[i], dp[j] + 1);
    return *max_element(dp.begin(), dp.end());
}

// O(n log n) patience sorting — contest standard
int lis_fast(vector<int>& arr) {
    vector<int> tails; // tails[i] = smallest tail of IS of length i+1
    for (int x : arr) {
        // Find first tail >= x (strictly increasing → lower_bound)
        auto it = lower_bound(tails.begin(), tails.end(), x);
        if (it == tails.end()) tails.push_back(x); // extend
        else                  *it = x;             // replace
    }
    return tails.size();
}

// Variant: Longest Non-Decreasing Subsequence → use upper_bound
int lnds_fast(vector<int>& arr) {
    vector<int> tails;
    for (int x : arr) {
        auto it = upper_bound(tails.begin(), tails.end(), x);
        if (it == tails.end()) tails.push_back(x);
        else                  *it = x;
    }
    return tails.size();
}

int main() {
    vector<int> arr = {10, 9, 2, 5, 3, 7, 101, 18};
    cout << lis_slow(arr) << "\n"; // 4
    cout << lis_fast(arr) << "\n"; // 4
}

#include <bits/stdc++.h>
using namespace std;

// 2D: O(n * W) time, O(n * W) space
int knapsack_2d(vector<int>& w, vector<int>& v, int W) {
    int n = w.size();
    vector<vector<int>> dp(n + 1, vector<int>(W + 1, 0));
    for (int i = 1; i <= n; i++)
        for (int j = 0; j <= W; j++) {
            dp[i][j] = dp[i-1][j]; // skip
            if (w[i-1] <= j)
                dp[i][j] = max(dp[i][j], dp[i-1][j - w[i-1]] + v[i-1]);
        }
    return dp[n][W];
}

// 1D space-optimized: iterate j RIGHT TO LEFT — critical!
int knapsack_1d(vector<int>& w, vector<int>& v, int W) {
    int n = w.size();
    vector<int> dp(W + 1, 0);
    for (int i = 0; i < n; i++)
        for (int j = W; j >= w[i]; j--) // RIGHT TO LEFT prevents reuse
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
    return dp[W];
}

int main() {
    vector<int> w = {2, 3, 4, 5};
    vector<int> v = {3, 4, 5, 6};
    int W = 8;
    cout << knapsack_2d(w, v, W) << "\n"; // 10
    cout << knapsack_1d(w, v, W) << "\n"; // 10
}

#include <bits/stdc++.h>
using namespace std;

// Minimum coins to make amount (unbounded knapsack, LEFT TO RIGHT)
int coinChange_min(vector<int>& coins, int amount) {
    const int INF = 1e9;
    vector<int> dp(amount + 1, INF);
    dp[0] = 0;
    for (int j = 1; j <= amount; j++)
        for (int c : coins)
            if (c <= j && dp[j - c] != INF)
                dp[j] = min(dp[j], dp[j - c] + 1);
    return dp[amount] == INF ? -1 : dp[amount];
}

// Number of ways to make amount (combination count)
// Order of loops matters: outer=coins avoids counting permutations
long long coinChange_ways(vector<int>& coins, int amount) {
    vector<long long> dp(amount + 1, 0);
    dp[0] = 1;
    for (int c : coins)           // outer = coins → combinations
        for (int j = c; j <= amount; j++)
            dp[j] += dp[j - c];
    return dp[amount];
}

// Number of ways treating ORDER as different (permutation count)
long long coinChange_perms(vector<int>& coins, int amount) {
    vector<long long> dp(amount + 1, 0);
    dp[0] = 1;
    for (int j = 1; j <= amount; j++) // outer = amount → permutations
        for (int c : coins)
            if (c <= j) dp[j] += dp[j - c];
    return dp[amount];
}

int main() {
    vector<int> coins = {1, 2, 5};
    int amount = 11;
    cout << coinChange_min(coins, amount) << "\n";   // 3  (5+5+1)
    cout << coinChange_ways(coins, amount) << "\n";  // 11 combinations
    cout << coinChange_perms(coins, amount) << "\n"; // 88 permutations
}

