// Given array of positive integers, determine if it can be
// partitioned into two subsets with equal sum.
// Constraints: n <= 200, arr[i] <= 100
// Input:  arr = {1, 5, 11, 5}
// Output: true  (subsets {1,5,5} and {11})
// Input:  arr = {1, 2, 3, 5}
// Output: false

sections.solution:
#include <bits/stdc++.h>
using namespace std;

bool canPartition(vector<int>& arr) {
    int total = accumulate(arr.begin(), arr.end(), 0);
    if (total % 2 != 0) return false;
    int target = total / 2;
    vector<bool> dp(target + 1, false);
    dp[0] = true;
    for (int x : arr)
        for (int j = target; j >= x; j--) // right to left: 0/1 knapsack
            dp[j] = dp[j] || dp[j - x];
    return dp[target];
}

int main() {
    vector<int> a = {1, 5, 11, 5};
    vector<int> b = {1, 2, 3, 5};
    cout << (canPartition(a) ? "true" : "false") << "\n";  // true
    cout << (canPartition(b) ? "true" : "false") << "\n";  // false
}

