// Given two strings word1 and word2, find the minimum number of
// operations (insert, delete, replace) to convert word1 to word2.
// Constraints: |word1|, |word2| <= 500
// Input:  word1="horse", word2="ros"
// Output: 3
// Input:  word1="intention", word2="execution"
// Output: 5

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int editDistance(const string& a, const string& b) {
    int n = a.size(), m = b.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));
    // Base cases
    for (int i = 0; i <= n; i++) dp[i][0] = i;
    for (int j = 0; j <= m; j++) dp[0][j] = j;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++)
            if (a[i-1] == b[j-1])
                dp[i][j] = dp[i-1][j-1]; // no operation needed
            else
                dp[i][j] = 1 + min({dp[i-1][j-1], // replace
                                     dp[i-1][j],   // delete from a
                                     dp[i][j-1]}); // insert into a
    return dp[n][m];
}

int main() {
    cout << editDistance("horse", "ros") << "\n";       // 3
    cout << editDistance("intention", "execution") << "\n"; // 5
    cout << editDistance("", "abc") << "\n";            // 3
}
